<?php
$pageTitle='Warehouses & Locations';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('org_structure');
$pdo=getDB();
$scopeOptions=scopeSelectOptions($pdo);
if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['form_type']??'')==='warehouse'){
  requireWarehouseCreationAllowed($pdo);
  $companyId=(int)($_POST['company_id']??0);$branchId=(int)($_POST['branch_id']??0);$code=trim((string)($_POST['warehouse_code']??''));$name=trim((string)($_POST['warehouse_name']??''));
  if($companyId<=0||$branchId<=0||$code===''||$name===''){flash('error','Company, branch, warehouse code, and name are required.');redirect(ADMIN_URL.'/erp/warehouses.php');}
  $stmt=$pdo->prepare('INSERT INTO '.table('warehouses').' (company_id,branch_id,warehouse_code,warehouse_name,address,status,is_default) VALUES (?,?,?,?,?,?,?)');
  $stmt->execute([$companyId,$branchId,$code,$name,trim((string)($_POST['address']??'')),trim((string)($_POST['status']??'active')),!empty($_POST['is_default'])?1:0]);
  $id=(int)$pdo->lastInsertId();if(!empty($_POST['is_default'])){$pdo->prepare('UPDATE '.table('warehouses').' SET is_default=CASE WHEN id=? THEN 1 ELSE 0 END WHERE branch_id=?')->execute([$id,$branchId]);}
  logActivity($pdo,'Organization','warehouse_created','Warehouse '.$code.' created.','warehouse',$id);flash('success','Warehouse created.');redirect(ADMIN_URL.'/erp/warehouses.php');
}
if($_SERVER['REQUEST_METHOD']==='POST' && ($_POST['form_type']??'')==='location'){
  $warehouseId=(int)($_POST['warehouse_id']??0);$code=trim((string)($_POST['location_code']??''));$name=trim((string)($_POST['location_name']??''));
  if($warehouseId<=0||$code===''||$name===''){flash('error','Warehouse, location code, and location name are required.');redirect(ADMIN_URL.'/erp/warehouses.php');}
  $stmt=$pdo->prepare('INSERT INTO '.table('warehouse_locations').' (warehouse_id,location_code,location_name,zone_type,status) VALUES (?,?,?,?,?)');
  $stmt->execute([$warehouseId,$code,$name,trim((string)($_POST['zone_type']??'general')),trim((string)($_POST['status']??'active'))]);
  logActivity($pdo,'Organization','warehouse_location_created','Warehouse location '.$code.' created.','warehouse_location',(int)$pdo->lastInsertId());flash('success','Warehouse location created.');redirect(ADMIN_URL.'/erp/warehouses.php');
}
$warehouses=$pdo->query('SELECT w.*,c.company_code,c.company_name,b.branch_code,b.branch_name,(SELECT COUNT(*) FROM '.table('warehouse_locations').' l WHERE l.warehouse_id=w.id) location_count,(SELECT COALESCE(SUM(quantity),0) FROM '.table('warehouse_stock').' ws WHERE ws.warehouse_id=w.id) stock_units FROM '.table('warehouses').' w LEFT JOIN '.table('companies').' c ON c.id=w.company_id LEFT JOIN '.table('branches').' b ON b.id=w.branch_id ORDER BY c.company_name,b.branch_name,w.is_default DESC,w.warehouse_name')->fetchAll();
$locations=$pdo->query('SELECT l.*,w.warehouse_code,w.warehouse_name FROM '.table('warehouse_locations').' l LEFT JOIN '.table('warehouses').' w ON w.id=l.warehouse_id ORDER BY w.warehouse_name,l.location_code')->fetchAll();
include dirname(__DIR__).'/header.php';
$warehouseLimitReached = function_exists('licenseTrialLimitReached') ? licenseTrialLimitReached('warehouses', $pdo) : false;
$warehouseLimit = function_exists('licensePlanLimit') ? licensePlanLimit('warehouses') : null;
$warehouseCount = function_exists('currentLicenseEntityCount') ? currentLicenseEntityCount('warehouses', $pdo) : count($warehouses);
?>
<?php if($warehouseLimitReached): ?>
<div class="alert alert-danger">
  <strong>Warehouse license limit reached.</strong>
  Current warehouses: <?php echo (int)$warehouseCount; ?> / <?php echo $warehouseLimit === null ? '∞' : (int)$warehouseLimit; ?>.
  Creating a new warehouse is blocked for this plan.
</div>
<?php endif; ?>
<div class="row g-4 mb-4"><div class="col-xl-6"><form method="post" class="card-admin p-4"><input type="hidden" name="form_type" value="warehouse"><div class="erp-kicker">Storage Network</div><h2 class="h5 mb-3">Create Warehouse</h2><div class="row g-3"><div class="col-lg-6"><label class="form-label">Company</label><select class="form-select" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>"><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select></div><div class="col-lg-6"><label class="form-label">Branch</label><select class="form-select" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>"><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-5"><label class="form-label">Code</label><input class="form-control" name="warehouse_code" required></div><div class="col-md-7"><label class="form-label">Name</label><input class="form-control" name="warehouse_name" required></div><div class="col-12"><label class="form-label">Address</label><textarea class="form-control" name="address" rows="2"></textarea></div><div class="col-md-6"><label class="form-label">Status</label><select class="form-select" name="status"><option value="active">Active</option><option value="inactive">Inactive</option></select></div><div class="col-md-6 d-flex align-items-end"><label class="form-check form-switch"><input class="form-check-input" type="checkbox" name="is_default" value="1"><span class="form-check-label">Default</span></label></div></div><button class="btn btn-brand mt-3" <?php echo $warehouseLimitReached ? 'disabled' : ''; ?>>Create Warehouse</button></form></div><div class="col-xl-6"><form method="post" class="card-admin p-4"><input type="hidden" name="form_type" value="location"><div class="erp-kicker">Bin / Zone Foundation</div><h2 class="h5 mb-3">Create Stock Location</h2><div class="mb-3"><label class="form-label">Warehouse</label><select class="form-select" name="warehouse_id"><?php foreach($scopeOptions['warehouses'] as $warehouse): ?><option value="<?php echo (int)$warehouse['id']; ?>"><?php echo esc($warehouse['warehouse_code'].' · '.$warehouse['warehouse_name']); ?></option><?php endforeach; ?></select></div><div class="row g-2"><div class="col-md-5"><label class="form-label">Code</label><input class="form-control" name="location_code" required></div><div class="col-md-7"><label class="form-label">Name</label><input class="form-control" name="location_name" required></div></div><div class="row g-2 mt-1"><div class="col-md-6"><label class="form-label">Zone Type</label><input class="form-control" name="zone_type" value="general"></div><div class="col-md-6"><label class="form-label">Status</label><select class="form-select" name="status"><option value="active">Active</option><option value="inactive">Inactive</option></select></div></div><button class="btn btn-brand mt-3">Create Location</button></form></div></div>
<div class="row g-4"><div class="col-xl-7"><div class="table-wrap table-responsive"><div class="table-toolbar"><div><div class="erp-kicker">Warehouse Directory</div><h2 class="h5 mb-0">Warehouses</h2></div><a class="btn btn-outline-primary" href="<?php echo esc(ADMIN_URL); ?>/erp/warehouse-stock.php"><?php echo t('Warehouse Stock', 'مخزون المخزن'); ?></a></div><table class="table align-middle"><thead><tr><th>Warehouse</th><th>Company / Branch</th><th>Locations</th><th>Stock</th></tr></thead><tbody><?php foreach($warehouses as $row): ?><tr><td><strong><?php echo esc($row['warehouse_code'].' · '.$row['warehouse_name']); ?></strong><?php if(!empty($row['is_default'])): ?><span class="badge bg-primary">Default</span><?php endif; ?></td><td><?php echo esc($row['company_code'].' · '.$row['company_name']); ?><div class="small text-secondary"><?php echo esc($row['branch_code'].' · '.$row['branch_name']); ?></div></td><td><?php echo (int)$row['location_count']; ?></td><td><?php echo number_format((float)$row['stock_units'],2); ?></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-xl-5"><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Locations</h2><table class="table align-middle"><thead><tr><th>Location</th><th>Warehouse</th><th>Type</th></tr></thead><tbody><?php foreach($locations as $row): ?><tr><td><strong><?php echo esc($row['location_code'].' · '.$row['location_name']); ?></strong></td><td><?php echo esc($row['warehouse_code'].' · '.$row['warehouse_name']); ?></td><td><?php echo esc($row['zone_type']); ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>